import json,sys
baseline=json.load(open('baseline-packages.json'))
after=json.load(sys.stdin)
def pkg_map(data):
    m={}
    for p in data['projects']:
        for f in p['frameworks']:
            for pkg in f.get('topLevelPackages',[]):
                m[(p['path'],pkg['id'])]=pkg['resolvedVersion']
    return m
b=pkg_map(baseline); a=pkg_map(after)
if b==a: print('All packages resolve identically to baseline.')
else: print('DIFFERENCES:',{k:(b.get(k),a.get(k)) for k in set(list(b)+list(a)) if b.get(k)!=a.get(k)})
"

